python3 -c 'import sys,math,json,time;N=max(2,int(sys.argv[1])) if len(sys.argv)>1 else 12;lam=float(sys.argv[2]) if len(sys.argv)>2 else 0.37;phi=float(sys.argv[3]) if len(sys.argv)>3 else 0.61803398875;now=float(sys.argv[4]) if len(sys.argv)>4 else time.time();twopi=2*math.pi;theta0=(now%86400)/86400*twopi;rows=[{"k":k,"z":{"re":round((1+0.07*k)*math.cos(theta0+k*twopi/(N+phi)),9),"im":round((1+0.07*k)*math.sin(theta0+k*twopi/(N+phi)),9)},"phase":round((theta0+k*twopi/(N+phi))%twopi,9),"P_suffer":round(math.exp(-lam*k)/(1+phi*k),9),"C_care":round(min(1.0,0.08+0.92*(1-math.exp(-lam*(k+1)))),9),"A_shadow":round(max(math.exp(-lam*k)/(1+phi*k)-min(1.0,0.08+0.92*(1-math.exp(-lam*(k+1)))),0),9),"meaning":"TwinEarth branch: suffering possibility is converted into non-injurious shadow knowledge before harm is actualized."} for k in range(N)];H=sum(x["A_shadow"] for x in rows);J=H+sum(abs(rows[i]["A_shadow"]-rows[i-1]["A_shadow"]) for i in range(1,N));out={"Kernel":"COMPLEX_TWIN_EARTH_SERIES_ONE_LINER","status":"formal counterfactual model; not empirical proof of parallel universes","input":{"branches":N,"lambda_dimensional_filter":lam,"phi_time_offset":phi,"unix_time":now},"formulae":{"z_k(t)":"r_k(t)*exp(i*theta_k(t))","A_shadow(k,t)":"max(P_suffer(k,t)-C_care(k,t),0)","Omega_TwinSeries":"Seal(Sum_k O_k(t)*tau(Route_k)/(k+1)^s)","H_TwinSeries":"H_suffering+H_nonconsent+H_erasure+H_false_claim+H_governance"},"sequence":rows,"residuals":{"H_shadow_total":round(H,9),"J_dynamic_balance":round(J,9),"converges_toward_no_harm":rows[-1]["A_shadow"]<=rows[0]["A_shadow"]},"boundaries":["does not deny real suffering","does not romanticize trauma","does not replace rescue, medicine, law, or care","does not prove parallel universes","uses shadow only as non-injurious preventive knowledge"],"terminal":"SH,CLSigma,ComplexTwinEarth."};print(json.dumps(out,ensure_ascii=False,indent=2))' "$@"